#include <stdio.h>
#include <unistd.h>
#include "sqlite3.h"

static int showResults(void *notUsed, int argc, char **argv, char **colv){
  int i;
  for(i=0; i<argc; i++){
    printf("%s = %s\n", colv[i], argv[i] ? argv[i] : "NULL");
  }
  return 0;
}

int main(int argc, char **argv){
  sqlite3 *db;
  int rc;
  char *zErrmsg = 0;
  unlink("x1.db");
  rc = sqlite3_open("x1.db", &db);
  if( rc ){
    fprintf(stderr, "cannot open 'x1.db'\n");
    return 1;
  }
  sqlite3_exec(db, 
    "CREATE TABLE foo (num INTEGER PRIMARY KEY,comment TEXT COLLATE NOCASE)"
    " WITHOUT ROWID;\n"
    "PRAGMA integrity_check;\n"
    "DROP TABLE foo;", showResults, 0, &zErrmsg);
  if( zErrmsg ){
    fprintf(stderr, "ERROR: %s\n", zErrmsg);
    sqlite3_free(zErrmsg);
    zErrmsg = 0;
  }
  sqlite3_exec(db,"PRAGMA integrity_check;", showResults, 0, &zErrmsg);
  if( zErrmsg ){
    fprintf(stderr, "ERROR: %s\n", zErrmsg);
    sqlite3_free(zErrmsg);
    zErrmsg = 0;
  }
  sqlite3_close(db);
  return 0;    
}
